SELECT ROW_NUMBER() OVER () AS sales_key, c."Customer ID" AS customer_key, p.product_id AS product_key, cat.category AS category_key, s.season AS season_key, c."Purchase Amount (USD)" AS purchase_amount_usd, 1 AS transaction_count, CASE WHEN LOWER(c."Discount Applied") = 'yes' THEN 1 ELSE 0 END AS discount_applied_count, CASE WHEN LOWER(c."Promo Code Used") = 'yes' THEN 1 ELSE 0 END AS promo_code_used_count, c."Review Rating" AS review_rating FROM staging_customer_details c LEFT JOIN staging_product_details p ON LOWER(TRIM(c."Item Purchased")) = LOWER(TRIM(p.product_name)) LEFT JOIN dim_category cat ON LOWER(TRIM(c."Category")) = LOWER(TRIM(cat.category)) LEFT JOIN dim_season s ON LOWER(TRIM(c."Season")) = LOWER(TRIM(s.season))